        <TestimonialCarousel className="mb-12 glassmorphism rounded shadow animate" />
      </div>
      <Footer className="bg-gradient-to-r from-[#6C5CE7] to-[#A29BFE] text-white p-12 pt-24 md:p-24 lg:p-36 xl:p-48 rounded-tl-16 rounded-tr-16" />
    </div>
  );
}

export default App;

