import React from 'react';
import { ArrowRight } from 'lucide-react';

function Navbar() {
  const [isActive, setIsActive] = React.useState(false);
  const [isDarkMode, setIsDarkMode] = React.useState(false);

  const toggleNavbar = () => {
    setIsActive(!isActive);
  };

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
  };

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-10 py-12 md:py-16 lg:py-20 ${
        isDarkMode
          ? 'bg-gradient-to-r from-[#2f4f7f] to-[#3b5bdb] text-[#ffd700]'
          : 'bg-[#F8FAFC] text-[#6C5CE7]'
      }`}
      aria-label="Main Navigation"
    >
      <div className="container mx-auto flex justify-between items-center px-12 md:px-24 lg:px-32">
        <a
          href="/"
          className={`text-4xl md:text-5xl lg:text-6xl font-bold font-montserrat ${
            isDarkMode ? 'text-[#ffd700]' : 'text-[#6C5CE7]'
          } transition-colors duration-300 hover:text-[#ffd700]`}
        >
          Veloce
        </a>
        <button
          className={`md:hidden flex justify-center items-center w-16 h-16 ${
            isDarkMode
              ? 'bg-gradient-to-r from-[#3b5bdb] to-[#2f4f7f] text-[#ffd700]'
              : 'bg-gradient-to-r from-[#6C5CE7] to-[#A29BFE] text-[#F8FAFC]'
          } rounded-4xl shadow-lg hover:shadow-2xl transition-shadow duration-300 active:scale-95`}
          onClick={toggleNavbar}
          aria-label="Toggle Navigation"
        >
          <ArrowRight
            className={`transition-transform ${isActive ? 'rotate-180' : ''} ${
              isDarkMode ? 'text-[#ffd700]' : 'text-[#F8FAFC]'
            }`}
            aria-hidden="true"
          />
        </button>
        <ul
          className={`md:flex hidden items-center justify-end gap-12 ${isActive ? 'flex flex-col absolute top-24 left-0 right-0' : ''} ${
            isDarkMode
              ? 'bg-[#2f4f7f] p-12 rounded-4xl shadow-2xl backdrop-blur-md'
              : 'bg-[#F8FAFC] p-12 rounded-4xl shadow-2xl backdrop-blur-md'
          }`}
          aria-label="Navigation Menu"
        >
          <li>
            <a
              href="/"
              className={`text-2xl md:text-3xl lg:text-4xl font-medium font-montserrat ${
                isDarkMode ? 'text-[#cbd5e1]' : 'text-[#6C5CE7]'
              } hover:text-[#ffd700] transition-colors duration-300`}
            >
              Home
            </a>
          </li>
          <li>
            <a
              href="#"
              className={`text-2xl md:text-3xl lg:text-4xl font-medium font-montserrat ${
                isDarkMode ? 'text-[#cbd5e1]' : 'text-[#6C5CE7]'
              } hover:text-[#ffd700] transition-colors duration-300`}
            >
              About
            </a>
          </li>
          <li>
            <a
              href="#"
              className={`text-2xl md:text-3xl lg:text-4xl font-medium font-montserrat ${
                isDarkMode ? 'text-[#cbd5e1]' : 'text-[#6C5CE7]'
              } hover:text-[#ffd700] transition-colors duration-300`}
            >
              Contact
            </a>
          </li>
          <li>
            <button
              className={`text-2xl md:text-3xl lg:text-4xl font-medium font-montserrat ${
                isDarkMode ? 'text-[#cbd5e1]' : 'text-[#6C5CE7]'
              } hover:text-[#ffd700] transition-colors duration-300`}
              onClick={toggleDarkMode}
            >
              {isDarkMode ? 'Light Mode' : 'Dark Mode'}
            </button>
          </li>
        </ul>
      </div>
    </nav>
  );
}

export default Navbar;

