import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const testimonials = [
    {
      id: 1,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'John Doe',
    },
    {
      id: 2,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Jane Doe',
    },
    {
      id: 3,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Bob Smith',
    },
  ];

  const [activeTestimonial, setActiveTestimonial] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setActiveTestimonial((prevActiveTestimonial) => (prevActiveTestimonial + 1) % testimonials.length);
    }, 5000);

    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <section
      className="bg-[#F8FAFC] py-20 md:py-24 lg:py-32 xl:py-40"
      aria-label="Testimonials Section"
    >
      <div className="container mx-auto flex flex-col items-center justify-center gap-16 md:gap-20 lg:gap-24 xl:gap-32">
        <h2
          className="text-4xl md:text-6xl lg:text-8xl font-bold text-[#6C5CE7] transition-all duration-500"
          style={{
            textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
          }}
        >
          What Our Customers Say
        </h2>
        <div className="flex flex-col items-center justify-center gap-12 md:gap-16 lg:gap-20 xl:gap-24">
          {testimonials.map((testimonial, index) => (
            <div
              key={testimonial.id}
              className={`${
                activeTestimonial === index
                  ? 'opacity-100 scale-100'
                  : 'opacity-50 scale-90'
              } transition-all duration-500 rounded-4xl bg-[#FFFFFF] bg-opacity-20 backdrop-blur-md p-12 md:p-16 lg:p-20 xl:p-24 shadow-lg shadow-[#A29BFE]`}
              style={{
                boxShadow: '0px 20px 40px rgba(0, 0, 0, 0.1)',
                background: 'linear-gradient(180deg, #FFFFFF 0%, #FFFFFF 100%)',
                backdropFilter: 'blur(20px)',
              }}
            >
              <p
                className="text-3xl md:text-5xl lg:text-7xl text-[#6C5CE7] font-inter text-center"
                style={{
                  textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
                }}
              >
                {testimonial.text}
              </p>
              <p
                className="text-2xl md:text-3xl lg:text-5xl text-[#A29BFE] font-inter text-center mt-8 md:mt-10 lg:mt-12 xl:mt-16"
                style={{
                  textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
                }}
              >
                - {testimonial.author}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;
